namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and communication." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on civilization." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Specializes in artificial intelligence and machine learning. Published over 50 peer-reviewed papers.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor", Bio = "Expert in distributed systems and cloud computing with 15 years of industry experience.", Email = "rmartinez@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Thompson", Title = "Professor", Bio = "Research focuses on abstract algebra and number theory. NSF CAREER award recipient.", Email = "sthompson@university.edu" },
            new() { Id = 4, Name = "Dr. James Wilson", Title = "Assistant Professor", Bio = "Quantum mechanics researcher with publications in Nature and Physical Review Letters.", Email = "jwilson@university.edu" },
            new() { Id = 5, Name = "Dr. Emily Brooks", Title = "Professor", Bio = "Award-winning author and specialist in contemporary American literature.", Email = "ebrooks@university.edu" },
            new() { Id = 6, Name = "Dr. Michael Davis", Title = "Associate Professor", Bio = "Historian specializing in early modern Europe and the Atlantic world.", Email = "mdavis@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search, knowledge representation, machine learning, and neural networks.", Credits = 4, Schedule = "TTh 1:00–2:20 PM", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 3, Code = "CS 350", Title = "Distributed Systems", Description = "Principles of distributed computing: consensus, replication, fault tolerance, and scalable architectures.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", DepartmentId = 1, Instructor = _instructors[1], Department = _departments[0] },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "MWF 10:00–10:50 AM", DepartmentId = 2, Instructor = _instructors[2], Department = _departments[1], IsFeatured = true },
            new() { Id = 5, Code = "MATH 310", Title = "Abstract Algebra", Description = "Groups, rings, fields, and their applications in modern mathematics and computer science.", Credits = 3, Schedule = "TTh 10:00–11:20 AM", DepartmentId = 2, Instructor = _instructors[2], Department = _departments[1] },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introductory physics.", Credits = 4, Schedule = "MWF 8:00–8:50 AM + Lab Th 2:00–4:50 PM", DepartmentId = 3, Instructor = _instructors[3], Department = _departments[2] },
            new() { Id = 7, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Wave functions, Schrödinger equation, angular momentum, and quantum measurement theory.", Credits = 4, Schedule = "TTh 9:00–10:20 AM", DepartmentId = 3, Instructor = _instructors[3], Department = _departments[2], IsFeatured = true },
            new() { Id = 8, Code = "ENG 201", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present day.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", DepartmentId = 4, Instructor = _instructors[4], Department = _departments[3] },
            new() { Id = 9, Code = "ENG 315", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry. Students produce and critique original work.", Credits = 3, Schedule = "TTh 3:00–4:20 PM", DepartmentId = 4, Instructor = _instructors[4], Department = _departments[3] },
            new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "Major civilizations, cultures, and events from prehistory through the early modern period.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", DepartmentId = 5, Instructor = _instructors[5], Department = _departments[4] },
            new() { Id = 11, Code = "HIST 250", Title = "Early Modern Europe", Description = "European history from the Renaissance through the Enlightenment, covering political, social, and cultural transformations.", Credits = 3, Schedule = "TTh 11:00 AM–12:20 PM", DepartmentId = 5, Instructor = _instructors[5], Department = _departments[4], IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return GetCourse(request.CourseId) is not null
            && !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId);
    }
}

